#include <stdio.h>
#include <stdlib.h>

int maxGamesWon(int* piles, int n) {
    int* dp = (int*)malloc(n * sizeof(int));
    dp[0] = 0;
    for (int i = 1; i < n; i++) {
        dp[i] = dp[i - 1];
        for (int j = 0; j < i; j++) {
            if (piles[i] == piles[j]) {
                dp[i] = (dp[i] > dp[j] + 1) ? dp[i] : dp[j] + 1;
            }
        }
    }
    int maxGames = dp[n - 1];
    free(dp);
    return maxGames;
}

int main() {
    int n;
    scanf("%d", &n);
    int* piles = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &piles[i]);
    }
    printf("%d\n", maxGamesWon(piles, n));
    free(piles);
    return 0;
}

