#include <iostream>
#include <vector>
using namespace std;

int maxGamesWon(vector<int>& piles) {
    int n = piles.size();
    vector<int> dp(n, 0);
    for (int i = 1; i < n; i++) {
        dp[i] = dp[i - 1];
        for (int j = 0; j < i; j++) {
            if (piles[i] == piles[j]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }
    return dp[n - 1];
}

int main() {
    int n;
    cin >> n;
    vector<int> piles(n);
    for (int i = 0; i < n; i++) {
        cin >> piles[i];
    }
    cout << maxGamesWon(piles) << endl;
    return 0;
}

